const body = $input.first().json.body || $input.first().json;

const data = {
  minerId: body.miner_id || 'UNKNOWN',
  helmetId: body.helmet_id || 'H-001',
  timestamp: body.timestamp || new Date().toISOString(),
  location: body.location || 'Zone-Unknown',
  sensors: {
    methane: parseFloat(body.methane_ppm || 0),
    co: parseFloat(body.co_ppm || 0),
    temperature: parseFloat(body.temperature_c || 0),
    shockDetected: body.shock_detected === true || body.shock_detected === 'true',
    shockForce: parseFloat(body.shock_force_g || 0),
    pulseRate: parseFloat(body.pulse_bpm || 0),
    emergencyButton: body.emergency_button === true || body.emergency_button === 'true'
  }
};

// Evaluate alert conditions
const alerts = [];

if (data.sensors.methane > 1000) alerts.push({ type: 'GAS_CRITICAL', sensor: 'Methane', value: data.sensors.methane, unit: 'ppm', threshold: 1000 });
else if (data.sensors.methane > 500) alerts.push({ type: 'GAS_WARNING', sensor: 'Methane', value: data.sensors.methane, unit: 'ppm', threshold: 500 });

if (data.sensors.co > 50) alerts.push({ type: 'GAS_CRITICAL', sensor: 'Carbon Monoxide', value: data.sensors.co, unit: 'ppm', threshold: 50 });
else if (data.sensors.co > 25) alerts.push({ type: 'GAS_WARNING', sensor: 'Carbon Monoxide', value: data.sensors.co, unit: 'ppm', threshold: 25 });

if (data.sensors.temperature > 45) alerts.push({ type: 'HEAT_CRITICAL', sensor: 'Temperature', value: data.sensors.temperature, unit: '°C', threshold: 45 });
else if (data.sensors.temperature > 38) alerts.push({ type: 'HEAT_WARNING', sensor: 'Temperature', value: data.sensors.temperature, unit: '°C', threshold: 38 });

if (data.sensors.shockDetected) alerts.push({ type: 'SHOCK_DETECTED', sensor: 'Shock', value: data.sensors.shockForce, unit: 'g', threshold: 0 });

if (data.sensors.pulseRate > 120) alerts.push({ type: 'PULSE_HIGH', sensor: 'Pulse', value: data.sensors.pulseRate, unit: 'bpm', threshold: 120 });
else if (data.sensors.pulseRate < 50 && data.sensors.pulseRate > 0) alerts.push({ type: 'PULSE_LOW', sensor: 'Pulse', value: data.sensors.pulseRate, unit: 'bpm', threshold: 50 });

if (data.sensors.emergencyButton) alerts.push({ type: 'EMERGENCY_MANUAL', sensor: 'Emergency Button', value: 1, unit: 'triggered', threshold: 0 });

const hasCritical = alerts.some(a => a.type.includes('CRITICAL') || a.type === 'EMERGENCY_MANUAL' || a.type === 'SHOCK_DETECTED');
const hasWarning = alerts.some(a => a.type.includes('WARNING'));

return [{ json: { ...data, alerts, hasCritical, hasWarning, hasAlerts: alerts.length > 0 } }];

const data = $input.first().json;
const criticalAlerts = data.alerts.filter(a => a.type.includes('CRITICAL') || a.type === 'EMERGENCY_MANUAL' || a.type === 'SHOCK_DETECTED');
const alertSummary = criticalAlerts.map(a => `${a.sensor}: ${a.value}${a.unit}`).join(', ');

return [{
  json: {
    ...data,
    smsMessage: `🚨 CRITICAL ALERT - Miner ${data.minerId} | Helmet ${data.helmetId} | Location: ${data.location} | Issues: ${alertSummary} | Time: ${data.timestamp}`,
    emailSubject: `[CRITICAL] Smart Helmet Alert - Miner ${data.minerId}`,
    emailBody: `CRITICAL SAFETY ALERT

Miner ID: ${data.minerId}
Helmet ID: ${data.helmetId}
Location: ${data.location}
Timestamp: ${data.timestamp}

Critical Issues Detected:
${criticalAlerts.map(a => `- ${a.sensor}: ${a.value} ${a.unit} (Threshold: ${a.threshold} ${a.unit})`).join('
')}

All Sensor Readings:
- Methane: ${data.sensors.methane} ppm
- CO: ${data.sensors.co} ppm
- Temperature: ${data.sensors.temperature} °C
- Pulse Rate: ${data.sensors.pulseRate} bpm
- Shock Detected: ${data.sensors.shockDetected}
- Emergency Button: ${data.sensors.emergencyButton}

Immediate action required. Initiate evacuation protocol if needed.`,
    incidentSeverity: 'CRITICAL'
  }
}];

const data = $input.first().json;
const warningAlerts = data.alerts.filter(a => a.type.includes('WARNING'));
const alertSummary = warningAlerts.map(a => `${a.sensor}: ${a.value}${a.unit}`).join(', ');

return [{
  json: {
    ...data,
    smsMessage: `⚠️ WARNING - Miner ${data.minerId} | Location: ${data.location} | Issues: ${alertSummary}`,
    emailSubject: `[WARNING] Smart Helmet Alert - Miner ${data.minerId}`,
    emailBody: `SAFETY WARNING\n\nMiner ID: ${data.minerId}\nHelmet ID: ${data.helmetId}\nLocation: ${data.location}\nTimestamp: ${data.timestamp}\n\nWarning Issues:\n${warningAlerts.map(a => `- ${a.sensor}: ${a.value} ${a.unit} (Threshold: ${a.threshold} ${a.unit})`).join('\n')}\n\nPlease monitor the situation closely.`,
    incidentSeverity: 'WARNING'
  }
}];

const data = $input.first().json;
const severity = data.incidentSeverity || (data.hasAlerts ? 'WARNING' : 'NORMAL');

return [{
  json: {
    incident_id: `INC-${Date.now()}`,
    miner_id: data.minerId,
    helmet_id: data.helmetId,
    timestamp: data.timestamp,
    location: data.location,
    severity: severity,
    alerts: JSON.stringify(data.alerts),
    methane_ppm: data.sensors.methane,
    co_ppm: data.sensors.co,
    temperature_c: data.sensors.temperature,
    shock_detected: data.sensors.shockDetected,
    shock_force_g: data.sensors.shockForce,
    pulse_bpm: data.sensors.pulseRate,
    emergency_button: data.sensors.emergencyButton,
    status: 'OPEN'
  }
}];

