const rows = $input.all().map(i => i.json);
const today = new Date().toISOString().slice(0, 10);

const todayRows = rows.filter(r => r.timestamp && r.timestamp.startsWith(today));
const critical = todayRows.filter(r => r.severity === 'CRITICAL').length;
const warnings = todayRows.filter(r => r.severity === 'WARNING').length;
const emergencies = todayRows.filter(r => r.emergency_button === 'true' || r.emergency_button === true).length;
const shocks = todayRows.filter(r => r.shock_detected === 'true' || r.shock_detected === true).length;

const uniqueMiners = [...new Set(todayRows.map(r => r.miner_id))];

const report = `
===== DAILY SAFETY REPORT =====
Date: ${today}
Generated: ${new Date().toISOString()}

SUMMARY
-------
Total Events Today: ${todayRows.length}
Critical Incidents: ${critical}
Warning Alerts: ${warnings}
Emergency Button Activations: ${emergencies}
Shock/Fall Events: ${shocks}
Miners Monitored: ${uniqueMiners.length} (${uniqueMiners.join(', ')})

ACTION REQUIRED: ${critical > 0 ? 'YES - ' + critical + ' critical incidents need review' : 'None'}

Please review the full incident log in Google Sheets for details.
================================
`;

return [{ json: { report, date: today, critical, warnings, totalEvents: todayRows.length } }];
